            // Attacker gets back at most 1 ETH (their own deposit), not 5+ ETH
            require(attackerBal <= 1 ether, "DRAINED: attack succeeded!");
            success = true;
        } catch {
            // Expected: revert due to reentrancy guard
            success = false;
